const yahooFinance = require('yahoo-finance2').default;

async function test() {
  try {
    console.log("Searching for Apple...");
    const searchRes = await yahooFinance.search('Apple');
    console.log("Search Result keys:", Object.keys(searchRes));
    if (searchRes.quotes && searchRes.quotes.length > 0) {
      const ticker = searchRes.quotes[0].symbol;
      console.log("First quote symbol:", ticker);

      console.log(`Fetching quote for ${ticker}...`);
      const quote = await yahooFinance.quote(ticker);
      console.log("Quote fields (subset):", {
        symbol: quote.symbol,
        longName: quote.longName,
        regularMarketPrice: quote.regularMarketPrice,
        currency: quote.currency,
        marketCap: quote.marketCap,
        forwardPE: quote.forwardPE
      });

      console.log(`Fetching quoteSummary for ${ticker}...`);
      const summary = await yahooFinance.quoteSummary(ticker, {
        modules: [ 'financialData', 'price', 'defaultKeyStatistics', 'earnings' ]
      });
      console.log("Summary keys:", Object.keys(summary));
    }
  } catch (err) {
    console.error("Error in yahoo-finance:", err);
  }
}

test();

