/* LangGraph Node Visualizer */
.graph-container {
  display: flex;
  justify-content: space-between;
  align-items: center;
  padding: 16px 12px;
  background: rgba(15, 23, 42, 0.5);
  border-radius: 12px;
  border: 1px solid var(--border-color);
  overflow-x: auto;
  gap: 16px;
}

.graph-node {
  display: flex;
  flex-direction: column;
  align-items: center;
  gap: 8px;
  position: relative;
  min-width: 90px;
}

.graph-node-circle {
  width: 40px;
  height: 40px;
  border-radius: 50%;
  background: rgba(51, 65, 85, 0.5);
  border: 2px solid var(--text-muted);
  display: flex;
  align-items: center;
  justify-content: center;
  color: var(--text-secondary);
  font-weight: bold;
  font-size: 0.85rem;
  transition: all var(--transition-normal);
}

.graph-node-label {
  font-size: 0.75rem;
  font-weight: 600;
  color: var(--text-secondary);
  text-align: center;
  white-space: nowrap;
}

.graph-node.active .graph-node-circle {
  background: var(--color-brand-glow);
  border-color: var(--color-brand);
  box-shadow: 0 0 15px var(--color-brand-glow);
  color: #fff;
  animation: pulseNode 1.5s infinite alternate;
}

.graph-node.active .graph-node-label {
  color: var(--color-brand-light);
  font-weight: 700;
}

.graph-node.completed .graph-node-circle {
  background: var(--color-success-bg);
  border-color: var(--color-success);
  color: var(--color-success);
}

.graph-node.completed .graph-node-label {
  color: var(--color-success);
}

.graph-edge-line {
  flex-grow: 1;
  height: 2px;
  background: var(--text-muted);
  opacity: 0.3;
  min-width: 20px;
  margin-top: -20px; /* aligns with center of circle */
}

.graph-edge-line.completed {
  background: var(--color-success);
  opacity: 0.7;
}

/* Recommendation Verdict Box */
.verdict-box {
  display: flex;
  align-items: center;
  justify-content: space-between;
  border-radius: 12px;
  padding: 24px;
  margin-bottom: 24px;
  border-left: 6px solid var(--text-muted);
  background: rgba(30, 41, 59, 0.25);
  box-shadow: 0 4px 20px -2px rgba(0,0,0,0.15);
}

.verdict-box.invest {
  border-left-color: var(--color-success);
  background: var(--color-success-bg);
  box-shadow: 0 4px 20px -2px var(--color-success-glow);
}

.verdict-box.pass {
  border-left-color: var(--color-danger);
  background: var(--color-danger-bg);
  box-shadow: 0 4px 20px -2px var(--color-danger-glow);
}

.verdict-info {
  display: flex;
  flex-direction: column;
  gap: 6px;
}

.verdict-badge-container {
  display: flex;
  align-items: center;
  gap: 12px;
}

.verdict-badge {
  padding: 6px 14px;
  border-radius: 30px;
  font-weight: 800;
  letter-spacing: 0.05em;
  font-size: 1.1rem;
}

.verdict-badge.invest-badge {
  background: var(--color-success);
  color: #064e3b;
}

.verdict-badge.pass-badge {
  background: var(--color-danger);
  color: #991b1b;
}

.verdict-text {
  font-size: 1.4rem;
  font-weight: 800;
  color: var(--text-primary);
}

.verdict-confidence {
  display: flex;
  flex-direction: column;
  align-items: flex-end;
  gap: 6px;
}

.verdict-confidence-label {
  font-size: 0.8rem;
  font-weight: 600;
  text-transform: uppercase;
  color: var(--text-secondary);
}

.verdict-confidence-value {
  font-size: 1.8rem;
  font-weight: 800;
}

.verdict-confidence-value.success {
  color: var(--color-success);
}
.verdict-confidence-value.danger {
  color: var(--color-danger);
}
.verdict-confidence-value.warning {
  color: var(--color-warning);
}

/* Tabs System */
.tabs-header {
  display: flex;
  border-bottom: 1px solid var(--border-color);
  gap: 12px;
  margin-bottom: 24px;
  overflow-x: auto;
}

.tab-btn {
  background: none;
  border: none;
  border-bottom: 2px solid transparent;
  color: var(--text-secondary);
  font-family: inherit;
  font-size: 0.95rem;
  font-weight: 600;
  padding: 12px 16px;
  cursor: pointer;
  transition: all var(--transition-fast);
  white-space: nowrap;
}

.tab-btn:hover {
  color: var(--text-primary);
}

.tab-btn.active {
  color: var(--color-brand-light);
  border-bottom-color: var(--color-brand);
}

/* History list */
.history-list {
  display: flex;
  flex-direction: column;
  gap: 10px;
  max-height: 300px;
  overflow-y: auto;
}

.history-item {
  display: flex;
  align-items: center;
  justify-content: space-between;
  padding: 12px 16px;
  background: rgba(15, 23, 42, 0.4);
  border: 1px solid var(--border-color);
  border-radius: 8px;
  cursor: pointer;
  transition: all var(--transition-fast);
}

.history-item:hover {
  background: rgba(30, 41, 59, 0.6);
  border-color: rgba(99, 102, 241, 0.2);
}

.history-item-info {
  display: flex;
  flex-direction: column;
  gap: 2px;
}

.history-item-ticker {
  font-weight: 700;
  font-size: 0.95rem;
}

.history-item-name {
  font-size: 0.75rem;
  color: var(--text-secondary);
}

.history-verdict-badge {
  padding: 3px 8px;
  border-radius: 4px;
  font-size: 0.7rem;
  font-weight: 800;
  text-transform: uppercase;
}

.history-verdict-badge.invest {
  background: rgba(16, 185, 129, 0.15);
  color: var(--color-success);
  border: 1px solid rgba(16, 185, 129, 0.3);
}

.history-verdict-badge.pass {
  background: rgba(244, 63, 94, 0.15);
  color: var(--color-danger);
  border: 1px solid rgba(244, 63, 94, 0.3);
}

/* Grid for Metrics */
.metrics-grid {
  display: grid;
  grid-template-columns: repeat(auto-fill, minmax(180px, 1fr));
  gap: 16px;
  margin-bottom: 24px;
}

.metric-card {
  background: rgba(15, 23, 42, 0.35);
  border: 1px solid var(--border-color);
  border-radius: 10px;
  padding: 16px;
  display: flex;
  flex-direction: column;
  gap: 6px;
}

.metric-label {
  font-size: 0.75rem;
  font-weight: 600;
  text-transform: uppercase;
  color: var(--text-secondary);
}

.metric-value {
  font-size: 1.3rem;
  font-weight: 750;
  color: var(--text-primary);
}

.metric-value.good {
  color: var(--color-success);
}

.metric-value.warn {
  color: var(--color-warning);
}

.metric-value.bad {
  color: var(--color-danger);
}

/* Thesis Columns */
.thesis-container {
  display: grid;
  grid-template-columns: 1fr 1fr;
  gap: 24px;
  margin-bottom: 24px;
}

@media (max-width: 768px) {
  .thesis-container {
    grid-template-columns: 1fr;
  }
}

.thesis-col {
  display: flex;
  flex-direction: column;
  gap: 16px;
}

.thesis-header-row {
  display: flex;
  align-items: center;
  gap: 8px;
  font-size: 1.1rem;
  font-weight: 700;
  padding-bottom: 8px;
  border-bottom: 1px solid var(--border-color);
}

.thesis-header-row.bull {
  color: var(--color-success);
}
.thesis-header-row.bear {
  color: var(--color-danger);
}

.thesis-list {
  display: flex;
  flex-direction: column;
  gap: 10px;
  list-style: none;
}

.thesis-list-item {
  display: flex;
  gap: 12px;
  font-size: 0.9rem;
  color: var(--text-secondary);
}

.thesis-list-item-bullet {
  margin-top: 4px;
  flex-shrink: 0;
}

.thesis-list-item-bullet.bull {
  color: var(--color-success);
}

.thesis-list-item-bullet.bear {
  color: var(--color-danger);
}

/* Report Sections formatting */
.report-section {
  display: flex;
  flex-direction: column;
  gap: 12px;
  margin-bottom: 24px;
}

.report-section h3 {
  font-size: 1.2rem;
  color: var(--color-brand-light);
  border-bottom: 1px solid rgba(148, 163, 184, 0.08);
  padding-bottom: 6px;
}

.report-section p {
  color: var(--text-secondary);
  font-size: 0.95rem;
  line-height: 1.7;
}

/* SWOT styling specific */
.swot-grid {
  display: grid;
  grid-template-columns: 1fr 1fr;
  gap: 20px;
}

@media (max-width: 768px) {
  .swot-grid {
    grid-template-columns: 1fr;
  }
}

.swot-card {
  padding: 16px;
  background: rgba(15, 23, 42, 0.25);
  border: 1px solid var(--border-color);
  border-radius: 8px;
}

.swot-card-title {
  font-weight: 700;
  font-size: 0.95rem;
  margin-bottom: 8px;
  text-transform: uppercase;
  letter-spacing: 0.05em;
}

.swot-card.swot-s { border-left: 4px solid var(--color-success); }
.swot-card.swot-w { border-left: 4px solid var(--color-danger); }
.swot-card.swot-o { border-left: 4px solid var(--color-brand); }
.swot-card.swot-t { border-left: 4px solid var(--color-warning); }

/* Animations */
@keyframes fadeIn {
  from { opacity: 0; transform: translateY(4px); }
  to { opacity: 1; transform: translateY(0); }
}

@keyframes pulseNode {
  from { box-shadow: 0 0 10px var(--color-brand-glow), 0 0 0 0px var(--color-brand-glow); }
  to { box-shadow: 0 0 20px var(--color-brand-glow), 0 0 0 8px rgba(99, 102, 241, 0); }
}

"use client";
import React from "react";
import { Check, Loader2 } from "lucide-react";

interface GraphVisualizerProps {
  currentNode: string;
}

const NODES = [
  { id: "resolveTicker", label: "Resolve Ticker" },
  { id: "fetchFinancials", label: "Fetch Financials" },
  { id: "searchNews", label: "Search News" },
  { id: "analyzeFundamentals", label: "Analyze Fundamentals" },
  { id: "assessRisks", label: "Assess Risks" },
  { id: "synthesizeDecision", label: "Decide & Synthesize" },
];

export default function GraphVisualizer({ currentNode }: GraphVisualizerProps) {
  // Index of current executing node
  const currentIndex = currentNode === "done" ? NODES.length : NODES.findIndex((n) => n.id === currentNode);

  return (
    <div className="card" style={{ display: "flex", flexDirection: "column", gap: "16px" }}>
      <h3 style={{ fontSize: "1.05rem", fontWeight: 700 }}>LangGraph Execution Pipeline</h3>
      <div className="graph-container">
        {NODES.map((node, index) => {
          const isActive = node.id === currentNode;
          const isCompleted = index < currentIndex;

          return (
            <React.Fragment key={node.id}>
              <div className={`graph-node ${isActive ? "active" : ""} ${isCompleted ? "completed" : ""}`}>
                <div className="graph-node-circle">
                  {isCompleted ? (
                    <Check size={16} strokeWidth={3} />
                  ) : isActive ? (
                    <Loader2 size={16} className="animate-spin" style={{ animation: "spin 1s linear infinite" }} />
                  ) : (
                    index + 1
                  )}
                </div>
                <span className="graph-node-label">{node.label}</span>
              </div>
              {index < NODES.length - 1 && (
                <div className={`graph-edge-line ${isCompleted ? "completed" : ""}`} />
              )}
            </React.Fragment>
          );
        })}
      </div>
      <style jsx global>{`
        @keyframes spin {
          from { transform: rotate(0deg); }
          to { transform: rotate(360deg); }
        }
      `}</style>
    </div>
  );
}

"use client";
import React from "react";
import { AreaChart, Area, XAxis, YAxis, Tooltip, ResponsiveContainer } from "recharts";
import { CompanyProfile, FinancialMetrics, ChartPoint } from "@/lib/agent/state";

interface FinancialDashboardProps {
  profile?: CompanyProfile;
  financials?: FinancialMetrics;
  chartData?: ChartPoint[];
}

export default function FinancialDashboard({ profile, financials, chartData }: FinancialDashboardProps) {
  if (!financials || !profile) return null;

  // Format big numbers (M, B, T)
  const formatNumber = (num?: number) => {
    if (num === undefined || num === null) return "N/A";
    const prefix = financials.currency === "USD" ? "$" : financials.currency + " ";
    if (num >= 1e12) return `${prefix}${(num / 1e12).toFixed(2)}T`;
    if (num >= 1e9) return `${prefix}${(num / 1e9).toFixed(2)}B`;
    if (num >= 1e6) return `${prefix}${(num / 1e6).toFixed(2)}M`;
    return prefix + num.toLocaleString();
  };

  const formatPercent = (val?: number) => {
    if (val === undefined || val === null) return "N/A";
    return `${(val * 100).toFixed(2)}%`;
  };

  // Determine styles for values
  const getPeClass = (pe?: number) => {
    if (!pe) return "";
    if (pe < 15) return "good";
    if (pe > 35) return "warn";
    return "";
  };

  const getDteClass = (dte?: number) => {
    if (dte === undefined) return "";
    if (dte < 60) return "good";
    if (dte > 150) return "bad";
    return "warn";
  };

  const getMarginClass = (margin?: number) => {
    if (margin === undefined) return "";
    if (margin > 0.20) return "good";
    if (margin < 0.05) return "bad";
    return "";
  };

  const getGrowthClass = (growth?: number) => {
    if (growth === undefined) return "";
    if (growth > 0.15) return "good";
    if (growth < 0) return "bad";
    return "";
  };

  const getRoeClass = (roe?: number) => {
    if (roe === undefined) return "";
    if (roe > 0.18) return "good";
    if (roe < 0.06) return "bad";
    return "";
  };

  return (
    <div style={{ display: "flex", flexDirection: "column", gap: "24px" }}>
      {/* Overview Card */}
      <div className="card">
        <div style={{ display: "flex", justifyContent: "space-between", alignItems: "flex-start", flexWrap: "wrap", gap: "16px", marginBottom: "16px" }}>
          <div>
            <h2 style={{ fontSize: "1.6rem", fontWeight: 800 }}>
              {profile.longName || "Company Profile"} {profile.symbol ? `(${profile.symbol})` : ""}
            </h2>
            <p style={{ color: "var(--text-secondary)", fontSize: "0.9rem", marginTop: "4px" }}>
              {profile.sector || "N/A"} • {profile.industry || "N/A"} 
              {profile.city && profile.country ? ` • ${profile.city}, ${profile.country}` : ""}
            </p>
          </div>
          <div style={{ textAlign: "right" }}>
            <div style={{ fontSize: "1.8rem", fontWeight: 800, color: "var(--text-primary)" }}>
              {financials.currency || "$"} {financials.currentPrice?.toFixed(2) || "0.00"}
            </div>
            {profile.website && (
              <a href={profile.website} target="_blank" rel="noopener noreferrer" style={{ fontSize: "0.8rem", display: "inline-block", marginTop: "4px" }}>
                Visit Corporate Site
              </a>
            )}
          </div>
        </div>
        {profile.summary && (
          <p style={{ color: "var(--text-secondary)", fontSize: "0.9rem", lineHeight: 1.6, display: "-webkit-box", WebkitLineClamp: 3, WebkitBoxOrient: "vertical", overflow: "hidden" }} title={profile.summary}>
            {profile.summary}
          </p>
        )}
      </div>

      {/* Charts Card */}
      {chartData && chartData.length > 0 && (
        <div className="card">
          <h3 style={{ fontSize: "1.1rem", marginBottom: "16px", fontWeight: 700 }}>12-Month Performance Chart ({financials.currency || "USD"})</h3>
          <div style={{ width: "100%", height: 260 }}>
            <ResponsiveContainer width="100%" height="100%">
              <AreaChart data={chartData} margin={{ top: 10, right: 10, left: -20, bottom: 0 }}>
                <defs>
                  <linearGradient id="colorPrice" x1="0" y1="0" x2="0" y2="1">
                    <stop offset="5%" stopColor="var(--color-brand)" stopOpacity={0.4}/>
                    <stop offset="95%" stopColor="var(--color-brand)" stopOpacity={0}/>
                  </linearGradient>
                </defs>
                <XAxis dataKey="date" stroke="var(--text-muted)" fontSize={11} tickLine={false} />
                <YAxis stroke="var(--text-muted)" fontSize={11} tickLine={false} domain={["auto", "auto"]} />
                <Tooltip
                  contentStyle={{ background: "#0f172a", borderColor: "var(--border-color)", borderRadius: "8px" }}
                  labelStyle={{ color: "var(--text-secondary)", fontSize: 11 }}
                  itemStyle={{ color: "var(--text-primary)", fontSize: 12, fontWeight: 700 }}
                />
                <Area type="monotone" dataKey="close" stroke="var(--color-brand)" strokeWidth={2.5} fillOpacity={1} fill="url(#colorPrice)" />
              </AreaChart>
            </ResponsiveContainer>
          </div>
        </div>
      )}

      {/* Metrics Grid */}
      <div className="metrics-grid">
        <div className="metric-card">
          <span className="metric-label">Market Capitalization</span>
          <span className="metric-value">{formatNumber(financials.marketCap)}</span>
        </div>
        <div className="metric-card">
          <span className="metric-label">P/E Ratio</span>
          <span className={`metric-value ${getPeClass(financials.peRatio)}`}>
            {financials.peRatio ? financials.peRatio.toFixed(2) : "N/A"}
          </span>
        </div>
        <div className="metric-card">
          <span className="metric-label">Debt-To-Equity</span>
          <span className={`metric-value ${getDteClass(financials.debtToEquity)}`}>
            {financials.debtToEquity !== undefined ? `${financials.debtToEquity.toFixed(1)}%` : "N/A"}
          </span>
        </div>
        <div className="metric-card">
          <span className="metric-label">Profit Margin</span>
          <span className={`metric-value ${getMarginClass(financials.profitMargin)}`}>
            {formatPercent(financials.profitMargin)}
          </span>
        </div>
        <div className="metric-card">
          <span className="metric-label">Revenue Growth</span>
          <span className={`metric-value ${getGrowthClass(financials.revenueGrowth)}`}>
            {formatPercent(financials.revenueGrowth)}
          </span>
        </div>
        <div className="metric-card">
          <span className="metric-label">Return on Equity (ROE)</span>
          <span className={`metric-value ${getRoeClass(financials.returnOnEquity)}`}>
            {formatPercent(financials.returnOnEquity)}
          </span>
        </div>
        <div className="metric-card">
          <span className="metric-label">Liquidity (Current Ratio)</span>
          <span className="metric-value">
            {financials.currentRatio ? financials.currentRatio.toFixed(2) : "N/A"}
          </span>
        </div>
        <div className="metric-card">
          <span className="metric-label">Free Cash Flow</span>
          <span className="metric-value">{formatNumber(financials.freeCashFlow)}</span>
        </div>
      </div>
    </div>
  );
}

"use client";
import React, { useState } from "react";
import { TrendingUp, AlertTriangle, Scale, Shield, Sparkles, BookOpen } from "lucide-react";
import { Recommendation, AnalysisSection, RiskSection, NewsResult, FinancialMetrics } from "@/lib/agent/state";

interface ReportViewerProps {
  recommendation?: Recommendation;
  analysis?: AnalysisSection;
  risks?: RiskSection;
  news?: NewsResult[];
  financials?: FinancialMetrics;
}

export default function ReportViewer({ recommendation, analysis, risks, news, financials }: ReportViewerProps) {
  const [activeTab, setActiveTab] = useState<"thesis" | "analysis" | "risks" | "summary">("thesis");

  if (!recommendation) {
    return (
      <div className="card" style={{ display: "flex", justifyContent: "center", alignItems: "center", minHeight: "300px", color: "var(--text-secondary)" }}>
        <p>Awaiting agent research analysis results...</p>
      </div>
    );
  }

  const isInvest = recommendation.decision === "INVEST";

  // Format price
  const formatVal = (val?: number) => {
    if (!val) return "N/A";
    const currency = financials?.currency || "$";
    return `${currency}${val.toLocaleString(undefined, { minimumFractionDigits: 2, maximumFractionDigits: 2 })}`;
  };

  const getConfClass = (score: number) => {
    if (score >= 80) return "success";
    if (score >= 50) return "warning";
    return "danger";
  };

  return (
    <div style={{ display: "flex", flexDirection: "column", gap: "24px" }}>
      {/* Verdict Glowing Container */}
      <div className={`verdict-box ${isInvest ? "invest" : "pass"}`}>
        <div className="verdict-info">
          <div className="verdict-badge-container">
            <span className={`verdict-badge ${isInvest ? "invest-badge" : "pass-badge"}`}>
              {recommendation.decision}
            </span>
            <span style={{ fontSize: "0.95rem", color: "var(--text-secondary)", fontWeight: 600 }}>
              Recommendation: {recommendation.verdict}
            </span>
          </div>
          <div style={{ marginTop: "12px", display: "flex", flexWrap: "wrap", gap: "24px" }}>
            <div>
              <div style={{ fontSize: "0.8rem", color: "var(--text-secondary)", textTransform: "uppercase", fontWeight: 600 }}>12M Price Target</div>
              <div style={{ fontSize: "1.2rem", fontWeight: 800, marginTop: "2px" }}>
                {formatVal(recommendation.targetPriceRange?.low)} - {formatVal(recommendation.targetPriceRange?.high)}
              </div>
            </div>
            {financials?.currentPrice && recommendation.targetPriceRange?.low && (
              <div>
                <div style={{ fontSize: "0.8rem", color: "var(--text-secondary)", textTransform: "uppercase", fontWeight: 600 }}>Current Value Deviation</div>
                <div style={{ fontSize: "1.2rem", fontWeight: 800, marginTop: "2px", color: isInvest ? "var(--color-success)" : "var(--color-danger)" }}>
                  {financials.currentPrice < recommendation.targetPriceRange.low 
                    ? `Discounted (${((1 - financials.currentPrice / recommendation.targetPriceRange.low) * 100).toFixed(1)}%)`
                    : `Premium`
                  }
                </div>
              </div>
            )}
          </div>
        </div>
        <div className="verdict-confidence">
          <span className="verdict-confidence-label">Conviction Score</span>
          <span className={`verdict-confidence-value ${getConfClass(recommendation.confidenceScore)}`}>
            {recommendation.confidenceScore}%
          </span>
        </div>
      </div>

      {/* Tabs */}
      <div className="card">
        <div className="tabs-header">
          <button className={`tab-btn ${activeTab === "thesis" ? "active" : ""}`} onClick={() => setActiveTab("thesis")}>
            Verdict & Thesis
          </button>
          <button className={`tab-btn ${activeTab === "analysis" ? "active" : ""}`} onClick={() => setActiveTab("analysis")}>
            Fundamental Analysis
          </button>
          <button className={`tab-btn ${activeTab === "risks" ? "active" : ""}`} onClick={() => setActiveTab("risks")}>
            Risks & SWOT
          </button>
          <button className={`tab-btn ${activeTab === "summary" ? "active" : ""}`} onClick={() => setActiveTab("summary")}>
            Executive Summary
          </button>
        </div>

        {/* Tab 1: Verdict & Thesis */}
        {activeTab === "thesis" && (
          <div className="thesis-container">
            <div className="thesis-col">
              <div className="thesis-header-row bull">
                <TrendingUp size={18} />
                <span>Bull Thesis (Key Drivers)</span>
              </div>
              <ul className="thesis-list">
                {recommendation.bullThesis?.map((item, idx) => (
                  <li key={idx} className="thesis-list-item">
                    <span className="thesis-list-item-bullet bull">▲</span>
                    <span>{item}</span>
                  </li>
                ))}
                {(!recommendation.bullThesis || recommendation.bullThesis.length === 0) && (
                  <li className="thesis-list-item">No core bull arguments listed.</li>
                )}
              </ul>
            </div>
            <div className="thesis-col">
              <div className="thesis-header-row bear">
                <AlertTriangle size={18} />
                <span>Bear Thesis (Key Risks)</span>
              </div>
              <ul className="thesis-list">
                {recommendation.bearThesis?.map((item, idx) => (
                  <li key={idx} className="thesis-list-item">
                    <span className="thesis-list-item-bullet bear">▼</span>
                    <span>{item}</span>
                  </li>
                ))}
                {(!recommendation.bearThesis || recommendation.bearThesis.length === 0) && (
                  <li className="thesis-list-item">No core bear arguments listed.</li>
                )}
              </ul>
            </div>
          </div>
        )}

        {/* Tab 2: Fundamental Analysis */}
        {activeTab === "analysis" && analysis && (
          <div style={{ display: "flex", flexDirection: "column", gap: "20px" }}>
            <div className="report-section">
              <h3 style={{ display: "flex", alignItems: "center", gap: "8px" }}>
                <Sparkles size={16} />
                Financial Health & Solvency
              </h3>
              <p>{analysis.financialHealth}</p>
            </div>
            <div className="report-section">
              <h3 style={{ display: "flex", alignItems: "center", gap: "8px" }}>
                <Scale size={16} />
                Market Moat & Competitive Dynamics
              </h3>
              <p>{analysis.marketPosition}</p>
            </div>
            <div className="report-section">
              <h3 style={{ display: "flex", alignItems: "center", gap: "8px" }}>
                <TrendingUp size={16} />
                Revenue Growth & Catalysts
              </h3>
              <p>{analysis.growthDrivers}</p>
            </div>
          </div>
        )}

        {/* Tab 3: Risks & SWOT */}
        {activeTab === "risks" && risks && (
          <div style={{ display: "flex", flexDirection: "column", gap: "24px" }}>
            <div className="swot-grid">
              <div className="swot-card swot-s">
                <div className="swot-card-title" style={{ color: "var(--color-success)" }}>Strengths & Moats</div>
                <p style={{ fontSize: "0.85rem", color: "var(--text-secondary)", lineHeight: 1.5 }}>
                  {analysis?.marketPosition || "Robust market size, pricing leadership, and brand value advantages."}
                </p>
              </div>
              <div className="swot-card swot-w">
                <div className="swot-card-title" style={{ color: "var(--color-danger)" }}>Weaknesses & Bottlenecks</div>
                <p style={{ fontSize: "0.85rem", color: "var(--text-secondary)", lineHeight: 1.5 }}>
                  {risks.competitiveThreats || "High input costs, competitor pricing actions, or narrow cash yields."}
                </p>
              </div>
              <div className="swot-card swot-o">
                <div className="swot-card-title" style={{ color: "var(--color-brand-light)" }}>Opportunities & Expansion</div>
                <p style={{ fontSize: "0.85rem", color: "var(--text-secondary)", lineHeight: 1.5 }}>
                  {analysis?.growthDrivers || "Pivots to emerging sectors, technology catalysts, or overseas expansion."}
                </p>
              </div>
              <div className="swot-card swot-t">
                <div className="swot-card-title" style={{ color: "var(--color-warning)" }}>Threats & Headwinds</div>
                <p style={{ fontSize: "0.85rem", color: "var(--text-secondary)", lineHeight: 1.5 }}>
                  {risks.macroFactors || "Geopolitical friction, regulatory controls, supply blocks, or inflation in 2026."}
                </p>
              </div>
            </div>

            <div className="report-section" style={{ marginTop: "12px" }}>
              <h3 style={{ display: "flex", alignItems: "center", gap: "8px" }}>
                <Shield size={16} />
                Risk Vector Diagnostics
              </h3>
              <div style={{ display: "flex", flexDirection: "column", gap: "16px", marginTop: "12px" }}>
                <div>
                  <h4 style={{ fontSize: "0.95rem", color: "var(--text-primary)", fontWeight: 700 }}>Competitor Threats</h4>
                  <p style={{ color: "var(--text-secondary)", fontSize: "0.9rem", marginTop: "4px" }}>{risks.competitiveThreats}</p>
                </div>
                <div>
                  <h4 style={{ fontSize: "0.95rem", color: "var(--text-primary)", fontWeight: 700 }}>Macroeconomic Variables (2026 Context)</h4>
                  <p style={{ color: "var(--text-secondary)", fontSize: "0.9rem", marginTop: "4px" }}>{risks.macroFactors}</p>
                </div>
                <div>
                  <h4 style={{ fontSize: "0.95rem", color: "var(--text-primary)", fontWeight: 700 }}>Compliance & Legal Exposure</h4>
                  <p style={{ color: "var(--text-secondary)", fontSize: "0.9rem", marginTop: "4px" }}>{risks.regulatoryRisks}</p>
                </div>
              </div>
            </div>
          </div>
        )}

        {/* Tab 4: Executive Summary */}
        {activeTab === "summary" && (
          <div className="report-section">
            <h3 style={{ display: "flex", alignItems: "center", gap: "8px" }}>
              <BookOpen size={16} />
              Investment Committee Memorandum
            </h3>
            <p style={{ whiteSpace: "pre-wrap", color: "var(--text-secondary)", fontSize: "0.95rem", lineHeight: 1.8, marginTop: "12px" }}>
              {recommendation.executiveSummary}
            </p>
          </div>
        )}
      </div>

      {/* News Links Card */}
      {news && news.length > 0 && (
        <div className="card">
          <h3 style={{ fontSize: "1.1rem", marginBottom: "16px", fontWeight: 700 }}>Gathered Research References</h3>
          <div style={{ display: "flex", flexDirection: "column", gap: "12px" }}>
            {news.map((item, idx) => (
              <div key={idx} style={{ paddingBottom: "12px", borderBottom: idx < news.length - 1 ? "1px solid var(--border-color)" : "none" }}>
                <a href={item.link} target="_blank" rel="noopener noreferrer" style={{ fontWeight: 700, fontSize: "0.95rem", display: "block" }}>
                  {item.title}
                </a>
                <p style={{ color: "var(--text-secondary)", fontSize: "0.85rem", marginTop: "4px", lineHeight: 1.4 }}>{item.snippet}</p>
              </div>
            ))}
          </div>
        </div>
      )}
    </div>
  );
}

